module top_module(
    input [3:0] data_in,
    input load, shift, reset, clk,
    output [3:0] data_out
);reg [3:0] obf_shift_reg;

always @(posedge clk) begin
    if (reset) begin
        obf_shift_reg <= 4'b0000;
    end else if (load) begin
        obf_shift_reg <= data_in;
    end else if (shift) begin
        obf_shift_reg <= {obf_shift_reg[2:0], 1'b0};
    end
end

assign data_out = obf_shift_reg;

endmodule
